// ── Nav ──────────────────────────────────────────────────────────────────────
function Nav({ onRegister }) {
  const [scrolled, setScrolled] = useState(false);
  const [menuOpen, setMenuOpen] = useState(false);
  const isMobile = useIsMobile();
  useEffect(() => {
    const h = () => setScrolled(window.scrollY > 60);
    window.addEventListener("scroll", h);
    return () => window.removeEventListener("scroll", h);
  }, []);

  const scroll = (id) => {
    const el = document.getElementById(id);
    if (el) window.scrollTo({ top: el.getBoundingClientRect().top + window.scrollY - 64, behavior: "smooth" });
    setMenuOpen(false);
  };

  return (
    <nav style={{
      position: "fixed", top: 0, left: 0, right: 0, zIndex: 100,
      background: scrolled || menuOpen ? "rgba(8,8,6,0.98)" : "transparent",
      backdropFilter: scrolled || menuOpen ? "blur(16px)" : "none",
      borderBottom: scrolled || menuOpen ? `1px solid ${C.border}` : "1px solid transparent",
      transition: "all 0.4s",
    }}>
      <div style={{ padding: isMobile ? "0 24px" : "0 48px", display: "flex", alignItems: "center", justifyContent: "space-between", height: 64 }}>
      <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
        <img src="data:image/png;base64," alt="The Enduro Project" style={{ height: 36, width: "auto" }} />
      </div>
      {isMobile ? (
          <button onClick={() => setMenuOpen(!menuOpen)} style={{ background: "none", border: "none", color: C.sand, cursor: "crosshair", fontSize: 22, lineHeight: 1, padding: 4 }}>
            {menuOpen ? "✕" : "☰"}
          </button>
        ) : (
          <div style={{ display: "flex", gap: 36, alignItems: "center" }}>
            {[["Story", "story"], ["Events", "events"], ["Merch", "merch"], ["Contact", "collaborate"]].map(([label, id]) => (
              <button key={id} onClick={() => scroll(id)}
                style={{ background: "none", border: "none", fontSize: 10, fontWeight: 700, letterSpacing: "0.18em", textTransform: "uppercase", color: C.grayMid, cursor: "crosshair", padding: 0, fontFamily: "'Switzer', sans-serif", transition: "color 0.2s" }}
                onMouseEnter={e => e.currentTarget.style.color = C.sand}
                onMouseLeave={e => e.currentTarget.style.color = C.grayMid}>
                {label}
              </button>
            ))}
            <button className="btn" onClick={onRegister} style={{ padding: "10px 20px", fontSize: 10 }}>Register</button>
          </div>
        )}
      </div>
      {isMobile && menuOpen && (
        <div style={{ padding: "20px 24px 28px", borderTop: `1px solid ${C.border}`, display: "flex", flexDirection: "column", gap: 20 }}>
          {[["Story", "story"], ["Events", "events"], ["Merch", "merch"], ["Contact", "collaborate"]].map(([label, id]) => (
            <button key={id} onClick={() => scroll(id)}
              style={{ background: "none", border: "none", fontSize: 13, fontWeight: 700, letterSpacing: "0.15em", textTransform: "uppercase", color: C.grayMid, cursor: "crosshair", padding: 0, fontFamily: "'Switzer', sans-serif", textAlign: "left" }}>
              {label}
            </button>
          ))}
          <button className="btn" onClick={() => { onRegister(); setMenuOpen(false); }} style={{ marginTop: 8 }}>Register</button>
        </div>
      )}
    </nav>
  );
}

